import { createRouter, createWebHistory } from 'vue-router';
import Home from '../components/Home.vue';
import Resume from '../components/Resume.vue';
import BCarePredictor from '../components/BcarePredictor.vue';
import DataVisualization from '../components/DataVisualization.vue';
import MentalHealth from '../components/MentalHealth.vue';
import SQLProject from '../components/SQLProject.vue';
import SkinAI from '../components/SkinAI.vue';
import SkinAIPredict from '../components/SkinAIPredict.vue';

const routes = [
  { path: '/', component: Home },
  { path: '/resume', component: Resume },
  { path: '/bcarepredictor', component: BCarePredictor },
  { path: '/datavisualization', component: DataVisualization },
  { path: '/mentalhealth', component: MentalHealth },
  { path: '/sqlproject', component: SQLProject },
  { path: '/skinai', component: SkinAI },
  { path: '/predict', name: 'SkinAIPredict', component: SkinAIPredict }, 
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL), 
  routes,
});

export default router;
