<script>
export default {
  data() {
    return {
      currentLanguage: this.$i18n.locale === 'en' ? 'PT' : 'EN', // Define o idioma atual baseado no locale inicial
    };
  },
  computed: {
    currentFlag() {
      // Retorna o caminho da bandeira com base no idioma atual
      return this.currentLanguage === 'EN' ? require('../assets/en-flag.png') : require('../assets/pt-flag.png');
    },
  },
  methods: {
    toggleLanguage() {
      const newLanguage = this.currentLanguage === 'EN' ? 'pt' : 'en'; // Alternar idioma
      this.$i18n.locale = newLanguage; // Alterar o idioma no i18n
      this.currentLanguage = newLanguage === 'en' ? 'PT' : 'EN'; // Atualizar o texto do botão
    },
  },
};
</script>

